let OfficeMetrics = (winStart:datetime, winEnd:datetime, days:real) { OfficeActivity | where TimeGenerated >= winStart and TimeGenerated < winEnd | where UserType == 'Regular' | where Operation in (MeaningfulOps) | extend UPN = tolower(tostring(UserId)) | where UPN !contains '#ext#' | where UPN !in (ExcludedUPNs) and UPN !in (ServiceAccountUPNs) | where '{W_TargetUser}' == '' or UPN == tolower('{W_TargetUser}') | summarize Events = count(), ActiveDays = dcount(bin(TimeGenerated, 1d)), Workloads = dcount(OfficeWorkload) by UPN | extend EventsPerDay = round(todouble(Events) / days, 2), ActiveDayRatio = round(todouble(ActiveDays) / days, 3) };
